// === CALCULATOR IMPLEMENTATION ===
const calculator = {
  calculate(inputs) {
    const validation = this.validate(inputs);
    if (validation.error) return validation;

    // Coerce numeric inputs
    let loanAmount = parseFloat(inputs.loanAmount);
    let interestRate = parseFloat(inputs.interestRate);
    let loanTerm = parseInt(inputs.loanTerm, 10);
    let extraPayment = parseFloat(inputs.extraPayment) || 0;
    let lumpSumPayment = parseFloat(inputs.lumpSumPayment) || 0;
    let biweekly = Boolean(inputs.biweeklyPayment);

    // Standard monthly payment (without extras)
    const monthlyRate = interestRate / 100 / 12;
    const numPayments = loanTerm * 12;
    let monthlyPayment;
    if (monthlyRate === 0) {
      monthlyPayment = loanAmount / numPayments;
    } else {
      monthlyPayment = loanAmount * monthlyRate * Math.pow(1 + monthlyRate, numPayments) /
                       (Math.pow(1 + monthlyRate, numPayments) - 1);
    }

    // Adjust for biweekly (effective monthly payment 13/12 of standard)
    let effectiveMonthlyPayment = biweekly ? monthlyPayment * (13 / 12) : monthlyPayment;
    effectiveMonthlyPayment += extraPayment;

    // Apply lump sum at start (reduce loan balance)
    let balance = Math.max(loanAmount - lumpSumPayment, 0);
    const maxBalance = balance; // record for total paid calculation

    let totalInterest = 0;
    let months = 0;
    let totalPaid = lumpSumPayment > loanAmount ? loanAmount : lumpSumPayment; // include lump sum amount (but cap if overpay)
    // If lump sum paid off loan, no further payments
    if (balance <= 0) {
      return {
        total: totalPaid, // entire cost is lump sum (capped to loan amount)
        breakdown: {
          monthlyPayment: Math.round(monthlyPayment * 100) / 100,
          totalInterest: 0,
          totalPaid: totalPaid,
          termMonths: 0,
          termYearsMonths: '0 years 0 months',
          standardTermMonths: numPayments,
          biweeklyEquivalent: biweekly,
        }
      };
    }

    // Amortization simulation
    while (balance > 0 && months < numPayments * 2) {
      const interest = balance * monthlyRate;
      totalInterest += interest;
      let principalPaid = effectiveMonthlyPayment - interest;
      if (principalPaid >= balance) {
        // Final payment: pay off remaining balance plus interest
        principalPaid = balance;
        totalPaid += interest + balance; // final month's payment = interest + remaining balance
        balance = 0;
        months++;
        break;
      }
      balance -= principalPaid;
      totalPaid += effectiveMonthlyPayment;
      months++;
    }

    // Term strings
    const termYears = Math.floor(months / 12);
    const termMonths = months % 12;
    const termStr = `${termYears} years ${termMonths} months`;

    return {
      total: Math.round(totalPaid * 100) / 100,
      breakdown: {
        monthlyPayment: Math.round(monthlyPayment * 100) / 100,
        effectiveMonthlyPayment: Math.round(effectiveMonthlyPayment * 100) / 100,
        totalInterest: Math.round(totalInterest * 100) / 100,
        totalPaid: Math.round(totalPaid * 100) / 100,
        termMonths: months,
        termYearsMonths: termStr,
        standardTermMonths: numPayments,
        biweeklyEquivalent: biweekly,
        extraPayment: extraPayment,
        lumpSumApplied: lumpSumPayment > loanAmount ? loanAmount : lumpSumPayment
      }
    };
  },

  validate(inputs) {
    const errors = [];
    // Check required fields
    if (inputs.loanAmount === undefined || inputs.loanAmount === null || inputs.loanAmount === '') {
      errors.push('Loan amount is required');
    }
    if (inputs.interestRate === undefined || inputs.interestRate === null || inputs.interestRate === '') {
      errors.push('Interest rate is required');
    }
    if (inputs.loanTerm === undefined || inputs.loanTerm === null || inputs.loanTerm === '') {
      errors.push('Loan term is required');
    }

    // If errors already, return
    if (errors.length > 0) return { error: errors.join('; ') };

    // Coerce for validation
    const loanAmount = parseFloat(inputs.loanAmount);
    const interestRate = parseFloat(inputs.interestRate);
    const loanTerm = parseInt(inputs.loanTerm, 10);
    const extraPayment = parseFloat(inputs.extraPayment) || 0;
    const lumpSumPayment = parseFloat(inputs.lumpSumPayment) || 0;

    if (isNaN(loanAmount) || loanAmount <= 0) {
      errors.push('Loan amount must be greater than 0');
    }
    if (isNaN(interestRate) || interestRate < 0) {
      errors.push('Interest rate cannot be negative');
    }
    if (isNaN(loanTerm) || loanTerm <= 0) {
      errors.push('Loan term must be greater than 0');
    }
    if (isNaN(extraPayment) || extraPayment < 0) {
      errors.push('Extra payment cannot be negative');
    }
    if (isNaN(lumpSumPayment) || lumpSumPayment < 0) {
      errors.push('Lump sum payment cannot be negative');
    }

    return errors.length > 0 ? { error: errors.join('; ') } : {};
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  },
};

// === PARAMS FOR REACT COMPONENT ===
const CALC_PARAMS = [
  { name:'loanAmount', label:'Loan Amount ($)', type:'number', placeholder:'e.g. 200000' },
  { name:'interestRate', label:'Interest Rate (%)', type:'number', placeholder:'e.g. 4.5', step:'0.1' },
  { name:'loanTerm', label:'Loan Term (years)', type:'number', placeholder:'e.g. 30' },
  { name:'extraPayment', label:'Extra Monthly Payment ($)', type:'number', placeholder:'e.g. 200' },
  { name:'lumpSumPayment', label:'Lump Sum Payment ($)', type:'number', placeholder:'e.g. 50000' },
  { name:'biweeklyPayment', label:'Biweekly Payments', type:'checkbox' },
];
